    // ANSI color codes
    localparam string ANSI_RESET     = "\033[0m";
    localparam string ANSI_GREEN     = "\033[32m";
    localparam string ANSI_RED       = "\033[31m";
    localparam string ANSI_BLUE      = "\033[34m";
    localparam string ANSI_BLINK     = "\033[5m";  // Slow blink

    // Function to print centered line with color and blink
    function automatic void print_centered_line(input string line, input string color, input int total_width);
        $display("%s%s%s%s", color, ANSI_BLINK, line, ANSI_RESET);
    endfunction


    function automatic void show_lab_title();
        $display("");
        $display("");
        foreach (LAB_TITLE[i]) begin
            $display("%s%s%s", ANSI_GREEN, LAB_TITLE[i], ANSI_RESET);
        end
        $display("");
        $display("");
    endfunction

    function automatic void show_report();
        $display("");  // Empty line for spacing
        
        foreach (REPORT_LINES[i]) begin
            $display("%s", REPORT_LINES[i]);
        end
        $display("");
    endfunction
    
    function automatic void show_result(
        input logic[1:0] sim_result
    );
        string color;
        string lines_to_show[];
        int img_width = 90;
        
        // First display the header image functions
        if (sim_result[1]) display_timeout();
        else if(sim_result[0]) display_fail();
        else display_pass();
        
        // Determine color based on sim_result
        if (sim_result[1]) begin
            color = ANSI_BLUE;       // Timeout - Blue
            lines_to_show = TIMEOUT_LINES;
        end else if (sim_result[0]) begin
            color = ANSI_RED;        // Fail - Red
            lines_to_show = FAIL_LINES;
        end else begin
            color = ANSI_GREEN;      // Pass - Green
            lines_to_show = PASS_LINES;
        end
        
        // Print SIM_HEADER centered with color and blink
        $display("");  // Empty line for spacing
        foreach (SIM_HEADER[i]) begin
            $display("%s%s%s", color, SIM_HEADER[i], ANSI_RESET);
        end
        // Print status lines (PASS/FAIL/TIMEOUT) centered with color and blink
        foreach (lines_to_show[i]) begin
            $display("%s%s%s", color, lines_to_show[i], ANSI_RESET);
        end
        
        // $display("");  // Empty line for spacing
        
        // foreach (REPORT_LINES[i]) begin
        //     $display("%s", REPORT_LINES[i]);
        // end
        // $display("");
    endfunction

